import google.generativeai as genai
import google.generativeai.protos as protos
import os, json

genai.configure(api_key=os.environ["GOOGLE_API_KEY"])

def get_weather(city: str, units: str = "celsius") -> dict:
    return {"city": city, "temperature": 22, "units": units, "condition": "Partly cloudy"}

TOOLS = [{
    "function_declarations": [{
        "name": "get_weather",
        "description": "Return current weather for a city.",
        "parameters": {
            "type": "object",
            "properties": {
                "city":  {"type": "string"},
                "units": {"type": "string", "enum": ["celsius", "fahrenheit"]}
            },
            "required": ["city"]
        }
    }]
}]

model = genai.GenerativeModel(model_name="gemini-1.5-flash", tools=TOOLS)
chat = model.start_chat()

# First turn
response = chat.send_message("What's the weather in Paris?")

for part in response.candidates[0].content.parts:
    if part.function_call:
        fc = part.function_call
        result = get_weather(**fc.args)

        # Build a FunctionResponse Part
        fn_response_part = protos.Part(
            function_response=protos.FunctionResponse(
                name=fc.name,
                response={"result": result}   # must be a dict
            )
        )

        # Send result back — ChatSession tracks history automatically
        final_response = chat.send_message(fn_response_part)
        print(final_response.text)

import google.generativeai as genai
import google.generativeai.protos as protos
import os

genai.configure(api_key=os.environ["GOOGLE_API_KEY"])

TOOLS = [{
    "function_declarations": [{
        "name": "add_numbers",
        "description": "Add two numbers together.",
        "parameters": {
            "type": "object",
            "properties": {
                "a": {"type": "number"},
                "b": {"type": "number"}
            },
            "required": ["a", "b"]
        }
    }]
}]

def add_numbers(a: float, b: float) -> dict:
    return {"sum": a + b}

TOOL_HANDLERS = {"add_numbers": add_numbers}

model = genai.GenerativeModel(model_name="gemini-1.5-flash", tools=TOOLS)

# Build the initial message list manually
contents = [{"role": "user", "parts": [{"text": "What is 47 plus 89?"}]}]

MAX_TURNS = 8
for _ in range(MAX_TURNS):
    response = model.generate_content(contents=contents)
    candidate = response.candidates[0]

    # Append the assistant turn
    contents.append({"role": "model", "parts": candidate.content.parts})

    # Check for function calls
    fn_calls = [p for p in candidate.content.parts if p.function_call]
    if not fn_calls:
        # Final text response
        for part in candidate.content.parts:
            if hasattr(part, "text") and part.text:
                print(part.text)
        break

    # Execute all function calls and collect results
    result_parts = []
    for part in fn_calls:
        fc = part.function_call
        handler = TOOL_HANDLERS.get(fc.name)
        result = handler(**fc.args) if handler else {"error": f"Unknown: {fc.name}"}
        result_parts.append(protos.Part(
            function_response=protos.FunctionResponse(
                name=fc.name,
                response={"result": result}
            )
        ))

    contents.append({"role": "function", "parts": result_parts})
else:
    print("Reached maximum turns without a final response.")

