import google.generativeai as genai
import google.generativeai.protos as protos
import os, concurrent.futures

genai.configure(api_key=os.environ["GOOGLE_API_KEY"])

def get_weather(city: str) -> dict:
    data = {"Paris": 18, "Tokyo": 28, "New York": 23}
    return {"city": city, "temp_c": data.get(city, 20)}

def get_population(city: str) -> dict:
    data = {"Paris": 2_161_000, "Tokyo": 13_960_000, "New York": 8_336_000}
    return {"city": city, "population": data.get(city, 0)}

HANDLERS = {"get_weather": get_weather, "get_population": get_population}

TOOLS = [{
    "function_declarations": [
        {"name": "get_weather",    "description": "Current weather.",
         "parameters": {"type": "object", "properties": {"city": {"type": "string"}}, "required": ["city"]}},
        {"name": "get_population", "description": "City population.",
         "parameters": {"type": "object", "properties": {"city": {"type": "string"}}, "required": ["city"]}},
    ]
}]

model = genai.GenerativeModel(model_name="gemini-1.5-flash", tools=TOOLS)
contents = [{"role": "user", "parts": [{"text": "What's the weather and population of Paris and Tokyo?"}]}]

response = model.generate_content(contents=contents)
contents.append({"role": "model", "parts": response.candidates[0].content.parts})

fn_calls = [p for p in response.candidates[0].content.parts if p.function_call]

def execute(part):
    fc = part.function_call
    result = HANDLERS[fc.name](**fc.args)
    return protos.Part(
        function_response=protos.FunctionResponse(name=fc.name, response={"result": result})
    )

with concurrent.futures.ThreadPoolExecutor() as pool:
    result_parts = list(pool.map(execute, fn_calls))

contents.append({"role": "function", "parts": result_parts})
final = model.generate_content(contents=contents)
print(final.candidates[0].content.parts[0].text)

import google.generativeai as genai
import google.generativeai.protos as protos
import os

genai.configure(api_key=os.environ["GOOGLE_API_KEY"])

def lookup_stock(ticker: str) -> dict:
    known = {"AAPL": 195.42, "MSFT": 415.20}
    if ticker not in known:
        raise ValueError(f"Unknown ticker: {ticker}")
    return {"ticker": ticker, "price": known[ticker], "currency": "USD"}

TOOL = [{
    "function_declarations": [{
        "name": "lookup_stock",
        "description": "Look up current stock price by ticker.",
        "parameters": {
            "type": "object",
            "properties": {"ticker": {"type": "string"}},
            "required": ["ticker"]
        }
    }]
}]

model = genai.GenerativeModel(model_name="gemini-1.5-flash", tools=TOOL)
chat = model.start_chat()

response = chat.send_message("What is the current price of XYZ stock?")

for part in response.candidates[0].content.parts:
    if part.function_call:
        fc = part.function_call
        try:
            result = lookup_stock(**fc.args)
            fn_resp = {"result": result}
        except ValueError as e:
            fn_resp = {"error": str(e)}  # let Gemini handle the failure

        followup = chat.send_message(protos.Part(
            function_response=protos.FunctionResponse(
                name=fc.name,
                response=fn_resp
            )
        ))
        print(followup.text)

import google.generativeai as genai
import google.generativeai.protos as protos
from dataclasses import dataclass
import os

genai.configure(api_key=os.environ["GOOGLE_API_KEY"])

@dataclass
class TokenTracker:
    prompt_tokens: int = 0
    output_tokens: int = 0
    turns: int = 0

    def record(self, response) -> None:
        meta = response.usage_metadata
        self.prompt_tokens += meta.prompt_token_count
        self.output_tokens += meta.candidates_token_count
        self.turns += 1

    def report(self) -> str:
        total = self.prompt_tokens + self.output_tokens
        return f"Turns: {self.turns} | Prompt: {self.prompt_tokens} | Output: {self.output_tokens} | Total: {total}"

def multiply(a: float, b: float) -> dict:
    return {"product": a * b}

TOOL = [{
    "function_declarations": [{
        "name": "multiply",
        "description": "Multiply two numbers.",
        "parameters": {
            "type": "object",
            "properties": {"a": {"type": "number"}, "b": {"type": "number"}},
            "required": ["a", "b"]
        }
    }]
}]

model = genai.GenerativeModel(model_name="gemini-1.5-flash", tools=TOOL)
tracker = TokenTracker()

contents = [{"role": "user", "parts": [{"text": "What is 123 multiplied by 456?"}]}]

while True:
    response = model.generate_content(contents=contents)
    tracker.record(response)
    parts = response.candidates[0].content.parts
    contents.append({"role": "model", "parts": parts})

    fn_calls = [p for p in parts if p.function_call]
    if not fn_calls:
        print(parts[0].text)
        break

    result_parts = []
    for p in fn_calls:
        fc = p.function_call
        result = multiply(**fc.args)
        result_parts.append(protos.Part(
            function_response=protos.FunctionResponse(name=fc.name, response={"result": result})
        ))
    contents.append({"role": "function", "parts": result_parts})

print(tracker.report())
